// playwright.config.ts
import { defineConfig, devices } from '@playwright/test';

export default defineConfig({
  // Test directory
  testDir: './tests',

  // Test match pattern
  testMatch: '**/*.spec.ts',

  // Global timeout for each test
  timeout: 30000,

  // Expect timeout for assertions
  expect: {
    timeout: 5000
  },

  // Run tests in parallel
  fullyParallel: true,

  // Fail fast on CI
  forbidOnly: !!process.env.CI,

  // Retry failed tests
  retries: process.env.CI ? 2 : 0,

  // Worker configuration
  workers: process.env.CI ? 1 : undefined,

  // Reporter configuration
  reporter: [
    ['html'],
    ['list'],
    ['json', { outputFile: 'results.json' }]
  ],

  // Global setup/teardown
  globalSetup: './global-setup.ts',
  globalTeardown: './global-teardown.ts',

  // Shared settings for all projects
  use: {
    baseURL: 'http://localhost:3000',
    trace: 'on-first-retry',
    screenshot: 'only-on-failure',
    video: 'retain-on-failure',
    actionTimeout: 10000,
  },

  // Browser projects
  projects: [
    {
      name: 'chromium',
      use: { ...devices['Desktop Chrome'] },
    },
    {
      name: 'firefox',
      use: { ...devices['Desktop Firefox'] },
    },
    {
      name: 'webkit',
      use: { ...devices['Desktop Safari'] },
    },
    {
      name: 'Mobile Chrome',
      use: { ...devices['Pixel 5'] },
    },
  ],

  // Web server for local development
  webServer: {
    command: 'npm run start',
    port: 3000,
    reuseExistingServer: !process.env.CI,
  },
});

// playwright.config.ts - Environment-based config
import { defineConfig } from '@playwright/test';

const isCI = !!process.env.CI;
const isProduction = process.env.NODE_ENV === 'production';

export default defineConfig({
  // Different settings for CI vs local
  retries: isCI ? 2 : 0,
  workers: isCI ? 1 : undefined,

  use: {
    baseURL: isProduction 
      ? 'https://production.example.com'
      : 'http://localhost:3000',

    // More aggressive timeouts locally
    actionTimeout: isCI ? 10000 : 5000,

    // Only capture traces on CI
    trace: isCI ? 'on' : 'on-first-retry',
  },

  // HTML report in CI, list locally
  reporter: isCI 
    ? [['html'], ['github']]
    : [['list'], ['html']],
});
